"use client";

import {
  forwardRef,
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from "react";
import type { MouseEvent } from "react";
import { cn } from "@/lib/utils";
import { TooltipProvider } from "@/components/ui/tooltip";
import {
  DEFAULT_FILE_TREE_LABELS,
  type FileTreeHandle,
  type FileTreeHeaderContext,
  type FileTreeProps,
  type FileTreeRow,
  type FsNode,
} from "./types";
import {
  FileTreeContext,
  type FileTreeContextValue,
} from "./hooks/use-file-tree-context";
import { useTreeState } from "./hooks/use-tree-state";
import { useTreeFlatten } from "./hooks/use-tree-flatten";
import { useLazyLoad } from "./hooks/use-lazy-load";
import { useTreeVirtual } from "./hooks/use-tree-virtual";
import { useTreeDrag } from "./hooks/use-tree-drag";
import { useTreeKeyboard } from "./hooks/use-tree-keyboard";
import { findNode, indexNodes } from "./lib/tree-utils";
import { validateNodes } from "./lib/validation";
import { FileTreeHeader } from "./parts/file-tree-header";
import { FileTreeRowList } from "./parts/file-tree-row-list";
import { FileTreeEmpty } from "./parts/file-tree-empty";
import { FileTreeLoading } from "./parts/file-tree-loading";
import { FileTreeDragOverlay } from "./parts/file-tree-drag-overlay";
import { FileTreeDeleteConfirm } from "./parts/file-tree-delete-confirm";
import { FileTreeContextMenu } from "./parts/file-tree-context-menu";

export const FileTree = forwardRef<FileTreeHandle, FileTreeProps>(
  function FileTree(props, ref) {
    const {
      nodes,
      loading = false,
      selectionMode = "single",
      selectedIds,
      defaultSelectedIds,
      onSelectedChange,
      expandedIds,
      defaultExpandedIds,
      onExpandedChange,
      onLoadChildren,
      onOpen,
      onCreate,
      onRename,
      onDelete,
      onMove,
      onRefresh,
      onExternalDrop,
      validateRename,
      iconForNode,
      renderRow,
      renderHeader,
      renderContextMenu,
      renderEmpty,
      renderLoading,
      renderDeleteConfirm,
      header = true,
      title,
      showNewFile = true,
      showNewFolder = true,
      showRefresh = true,
      showCollapseAll = true,
      contextMenu = true,
      contextMenuActions,
      showHidden = false,
      isHidden,
      sortNodes,
      indentGuides = true,
      rowHeight = 28,
      indent = 18,
      confirmDelete = true,
      enableInternalDrag = true,
      enableExternalDrop = true,
      virtualize = "auto",
      virtualizeThreshold = 200,
      className,
      style,
      labels: labelsOverride,
    } = props;

    const labels = useMemo(
      () => ({ ...DEFAULT_FILE_TREE_LABELS, ...labelsOverride }),
      [labelsOverride],
    );

    // ── Pending delete (alertdialog) ───────────────────────────────────────
    const [pendingDeleteIds, setPendingDeleteIds] = useState<string[]>([]);
    const requestDeleteConfirmation = useCallback(
      (ids: string[]) => setPendingDeleteIds(ids),
      [],
    );

    // ── State + actions ────────────────────────────────────────────────────
    const stateHook = useTreeState({
      nodes,
      selectionMode,
      selectedIds,
      defaultSelectedIds,
      onSelectedChange,
      expandedIds,
      defaultExpandedIds,
      onExpandedChange,
      onCreate,
      onDelete,
      onRefresh,
      confirmDelete,
      requestDeleteConfirmation,
    });

    // ── Lazy load wiring ───────────────────────────────────────────────────
    const lazy = useLazyLoad({
      onLoadChildren,
      setLoadingFolderIds: stateHook.setLoadingFolderIds,
    });

    // Auto-fire onLoadChildren when consumer expands a folder w/ children=undefined.
    useEffect(() => {
      if (!onLoadChildren) return;
      for (const id of stateHook.state.expandedIds) {
        const node = findNode(id, nodes);
        if (
          node &&
          node.type === "folder" &&
          node.children === undefined &&
          !lazy.errors.has(node.id)
        ) {
          lazy.load(node);
        }
      }
      // We intentionally exclude `lazy` from deps to avoid re-firing on
      // every error-state update. The fields we care about are above.
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [stateHook.state.expandedIds, nodes, onLoadChildren]);

    // ── Visible-row flatten ────────────────────────────────────────────────
    const rows = useTreeFlatten({
      nodes,
      expandedIds: stateHook.state.expandedIds,
      selectedIds: stateHook.state.selectedIds,
      focusedId: stateHook.state.focusedId,
      loadingFolderIds: stateHook.state.loadingFolderIds,
      showHidden,
      isHidden,
      sortNodes,
    });

    // ── Drag ───────────────────────────────────────────────────────────────
    const drag = useTreeDrag({
      nodes,
      enableInternalDrag,
      enableExternalDrop,
      selectedIds: stateHook.state.selectedIds,
      selectionMode,
      onMove,
      onExternalDrop,
      selectIds: stateHook.actions.select,
    });

    // ── Keyboard ───────────────────────────────────────────────────────────
    const kb = useTreeKeyboard({
      rows,
      focusedId: stateHook.state.focusedId,
      renamingId: stateHook.state.renamingId,
      selectionMode,
      selectedIds: stateHook.state.selectedIds,
      actions: stateHook.actions,
      onOpen,
    });

    // ── Validate nodes (dev) ───────────────────────────────────────────────
    useEffect(() => {
      if (process.env.NODE_ENV === "production") return;
      const warnings = validateNodes(nodes);
      for (const w of warnings) {
        console.warn("[file-tree]", w);
      }
    }, [nodes]);

    // ── Imperative handle ──────────────────────────────────────────────────
    useImperativeHandle(
      ref,
      () => ({
        state: stateHook.state,
        actions: stateHook.actions,
      }),
      [stateHook.state, stateHook.actions],
    );

    // ── Index for context-menu target lookup ───────────────────────────────
    const nodeIndex = useMemo(() => indexNodes(nodes), [nodes]);

    // ── Row click + double-click + chevron + context-menu ──────────────────
    const onRowClick = useCallback(
      (e: MouseEvent, row: FileTreeRow) => {
        if (selectionMode === "multi" && (e.metaKey || e.ctrlKey)) {
          const next = new Set(stateHook.state.selectedIds);
          if (next.has(row.node.id)) next.delete(row.node.id);
          else next.add(row.node.id);
          stateHook.actions.select(Array.from(next));
          stateHook.setSelectionAnchorId(row.node.id);
        } else if (selectionMode === "multi" && e.shiftKey) {
          const anchor = stateHook.getSelectionAnchorId();
          if (!anchor) {
            stateHook.actions.select(row.node.id);
            stateHook.setSelectionAnchorId(row.node.id);
          } else {
            const aIdx = rows.findIndex((r) => r.node.id === anchor);
            const bIdx = rows.findIndex((r) => r.node.id === row.node.id);
            if (aIdx !== -1 && bIdx !== -1) {
              const [from, to] = aIdx < bIdx ? [aIdx, bIdx] : [bIdx, aIdx];
              const ids = rows.slice(from, to + 1).map((r) => r.node.id);
              stateHook.actions.select(ids);
            }
          }
        } else {
          stateHook.actions.select(row.node.id);
          stateHook.setSelectionAnchorId(row.node.id);
        }
        stateHook.actions.focusNode(row.node.id);
      },
      [selectionMode, stateHook, rows],
    );

    const onChevronClick = useCallback(
      (_e: MouseEvent, row: FileTreeRow) => {
        if (row.node.type !== "folder") return;
        stateHook.actions.toggleExpand(row.node.id);
      },
      [stateHook.actions],
    );

    const onRowDoubleClick = useCallback(
      (_e: MouseEvent, row: FileTreeRow) => {
        if (row.node.type === "folder") {
          stateHook.actions.toggleExpand(row.node.id);
        } else {
          onOpen?.({ node: row.node });
        }
      },
      [stateHook.actions, onOpen],
    );

    const onRowContextMenu = useCallback(
      (_e: MouseEvent, row: FileTreeRow) => {
        if (!stateHook.state.selectedIds.has(row.node.id)) {
          stateHook.actions.select(row.node.id);
        }
        stateHook.actions.focusNode(row.node.id);
      },
      [stateHook.state.selectedIds, stateHook.actions],
    );

    const onRenameCommit = useCallback(
      (id: string, nextName: string) => {
        const node = findNode(id, nodes);
        if (node && onRename) onRename({ id, node, nextName });
        stateHook.actions.cancelRename();
      },
      [nodes, onRename, stateHook.actions],
    );

    const onRenameCancel = useCallback(() => {
      stateHook.actions.cancelRename();
    }, [stateHook.actions]);

    // ── Header context (for renderHeader slot) ─────────────────────────────
    const totalCount = stateHook.totalCount;
    const visibleCount = rows.length;

    const headerCtx: FileTreeHeaderContext = useMemo(
      () => ({
        state: stateHook.state,
        actions: stateHook.actions,
        totalCount,
        visibleCount,
        showNewFile,
        showNewFolder,
        showRefresh,
        showCollapseAll,
        title,
        labels,
      }),
      [
        stateHook.state,
        stateHook.actions,
        totalCount,
        visibleCount,
        showNewFile,
        showNewFolder,
        showRefresh,
        showCollapseAll,
        title,
        labels,
      ],
    );

    // ── Public Context value ───────────────────────────────────────────────
    const ctxValue: FileTreeContextValue = useMemo(
      () => ({
        state: stateHook.state,
        actions: stateHook.actions,
        rows,
        totalCount,
        visibleCount,
        showNewFile,
        showNewFolder,
        showRefresh,
        showCollapseAll,
        title,
        labels,
      }),
      [
        stateHook.state,
        stateHook.actions,
        rows,
        totalCount,
        visibleCount,
        showNewFile,
        showNewFolder,
        showRefresh,
        showCollapseAll,
        title,
        labels,
      ],
    );

    // ── Virtualization ─────────────────────────────────────────────────────
    const scrollRef = useRef<HTMLDivElement>(null);
    const v = useTreeVirtual({
      rows,
      scrollRef,
      mode: virtualize,
      threshold: virtualizeThreshold,
      rowHeight,
    });

    // ── Body content ───────────────────────────────────────────────────────
    let body: React.ReactNode;
    if (loading) {
      body = renderLoading?.() ?? <FileTreeLoading />;
    } else if (nodes.length === 0) {
      body =
        renderEmpty?.({
          actions: stateHook.actions,
          showNewFile,
          showNewFolder,
          labels,
        }) ?? <FileTreeEmpty />;
    } else {
      const list = (
        <div className="relative h-full min-h-0 flex-1">
          <FileTreeRowList
            rows={rows}
            rowHeight={rowHeight}
            indent={indent}
            indentGuides={indentGuides}
            iconForNode={iconForNode}
            renamingId={stateHook.state.renamingId}
            validateRename={validateRename}
            enableInternalDrag={enableInternalDrag}
            dragOver={drag.dragOver}
            loadErrors={lazy.errors}
            onRetryLoad={(nodeId) => {
              const node = findNode(nodeId, nodes);
              if (node) {
                lazy.clearError(nodeId);
                lazy.load(node);
              }
            }}
            labels={labels}
            virtualizer={v.active ? v.virtualizer : undefined}
            scrollRef={scrollRef}
            renderRow={renderRow}
            onRowClick={onRowClick}
            onChevronClick={onChevronClick}
            onRowDoubleClick={onRowDoubleClick}
            onRowContextMenu={onRowContextMenu}
            onRenameCommit={onRenameCommit}
            onRenameCancel={onRenameCancel}
            onRowDragStart={drag.onRowDragStart}
            onRowDragOver={drag.onRowDragOver}
            onRowDragLeave={drag.onRowDragLeave}
            onRowDrop={drag.onRowDrop}
            onRowDragEnd={drag.onRowDragEnd}
          />
        </div>
      );
      body = (
        <FileTreeContextMenu
          state={stateHook.state}
          actions={stateHook.actions}
          enabled={contextMenu}
          labels={labels}
          gates={{
            open: contextMenuActions?.open ?? true,
            newFile: contextMenuActions?.newFile ?? true,
            newFolder: contextMenuActions?.newFolder ?? true,
            rename: contextMenuActions?.rename ?? true,
            delete: contextMenuActions?.delete ?? true,
            refresh: contextMenuActions?.refresh ?? true,
          }}
          wired={{
            onOpen: !!onOpen,
            onCreate: !!onCreate,
            onRename: !!onRename,
            onDelete: !!onDelete,
            onRefresh: !!onRefresh,
          }}
          nodeIndex={nodeIndex}
          renderContextMenu={renderContextMenu}
        >
          {list}
        </FileTreeContextMenu>
      );
    }

    // ── Pending-delete dialog ──────────────────────────────────────────────
    const pendingNodes: FsNode[] = useMemo(
      () =>
        pendingDeleteIds
          .map((id) => nodeIndex.get(id))
          .filter((n): n is FsNode => Boolean(n)),
      [pendingDeleteIds, nodeIndex],
    );

    const onConfirmDelete = useCallback(() => {
      if (pendingDeleteIds.length === 0) return;
      onDelete?.({ ids: pendingDeleteIds });
      setPendingDeleteIds([]);
    }, [onDelete, pendingDeleteIds]);

    const onCancelDelete = useCallback(() => {
      setPendingDeleteIds([]);
    }, []);

    return (
      <FileTreeContext.Provider value={ctxValue}>
       <TooltipProvider delayDuration={400}>
        <div
          role="tree"
          tabIndex={0}
          aria-label={title ?? labels.title}
          className={cn(
            "relative flex h-full w-full flex-col overflow-hidden rounded-md border border-border/60 bg-background text-foreground outline-none",
            "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background",
            className,
          )}
          style={style}
          onKeyDown={kb.onKeyDown}
          onDragEnter={drag.onContainerDragEnter}
          onDragOver={drag.onContainerDragOver}
          onDragLeave={drag.onContainerDragLeave}
          onDrop={drag.onContainerDrop}
        >
          {header
            ? (renderHeader ? renderHeader(headerCtx) : <FileTreeHeader />)
            : null}
          {body}
          <FileTreeDragOverlay
            visible={drag.isExternalDragging}
            labels={labels}
          />
          {confirmDelete && pendingDeleteIds.length > 0 ? (
            renderDeleteConfirm ? (
              renderDeleteConfirm({
                ids: pendingDeleteIds,
                nodes: pendingNodes,
                onConfirm: onConfirmDelete,
                onCancel: onCancelDelete,
                labels,
              })
            ) : (
              <FileTreeDeleteConfirm
                open={true}
                ids={pendingDeleteIds}
                nodes={pendingNodes}
                labels={labels}
                onConfirm={onConfirmDelete}
                onCancel={onCancelDelete}
              />
            )
          ) : null}
        </div>
       </TooltipProvider>
      </FileTreeContext.Provider>
    );
  },
);

FileTree.displayName = "FileTree";

export { FileTree } from "./file-tree";
export { FileTreeHeader } from "./parts/file-tree-header";
export { FileTreeNewFileButton } from "./parts/file-tree-new-file-button";
export { FileTreeNewFolderButton } from "./parts/file-tree-new-folder-button";
export { FileTreeRefreshButton } from "./parts/file-tree-refresh-button";
export { FileTreeCollapseAllButton } from "./parts/file-tree-collapse-all-button";
export { useFileTree } from "./hooks/use-file-tree-context";
export { mergeLoadedChildren } from "./lib/tree-utils";
export { iconForExtension } from "./lib/icons";
export { DEFAULT_FILE_TREE_LABELS } from "./types";
export type {
  FsNode,
  FsNodeType,
  FileTreeProps,
  FileTreeHandle,
  FileTreeState,
  FileTreeActions,
  FileTreeRow,
  FileTreeSelectionMode,
  FileTreeDropPosition,
  FileTreeVirtualizeMode,
  FileTreeOpenArgs,
  FileTreeCreateArgs,
  FileTreeRenameArgs,
  FileTreeDeleteArgs,
  FileTreeMoveArgs,
  FileTreeRefreshArgs,
  FileTreeExternalDropArgs,
  FileTreeLoadChildrenArgs,
  FileTreeSelectionChangeArgs,
  FileTreeExpandedChangeArgs,
  FileTreeValidateRenameArgs,
  FileTreeIconForNodeArgs,
  FileTreeContextMenuItem,
  FileTreeContextMenuItemId,
  FileTreeHeaderContext,
  FileTreeContextMenuContext,
  FileTreeEmptyContext,
  FileTreeRowRenderArgs,
  FileTreeDeleteConfirmContext,
  FileTreeLabels,
} from "./types";

import type { CSSProperties, ReactNode, Ref } from "react";

export type FsNodeType = "file" | "folder";

/**
 * Hierarchical-node shape consumed by `<FileTree>`.
 *
 * `children` semantics:
 *  - `undefined` — unknown / not yet loaded → triggers `onLoadChildren` on first expand
 *  - `[]`        — known-empty folder → renders "(empty)" inline placeholder
 *  - `FsNode[]`  — pre-loaded children
 */
export interface FsNode {
  id: string;
  name: string;
  type: FsNodeType;
  parentId?: string | null;
  children?: FsNode[];
  ext?: string;
  size?: number;
  modifiedAt?: string;
  icon?: ReactNode;
  meta?: Record<string, unknown>;
}

export type FileTreeSelectionMode = "single" | "multi";
export type FileTreeDropPosition = "before" | "inside" | "after";
export type FileTreeVirtualizeMode = "auto" | "always" | "never";

/** Visible-row descriptor produced by the flattening pass. */
export interface FileTreeRow {
  node: FsNode;
  depth: number;
  expanded: boolean;
  selected: boolean;
  focused: boolean;
  hasChildren: boolean;
  childrenLoaded: boolean;
  loadingChildren: boolean;
  /** Position within the visible-rows array. */
  index: number;
  /** Number of visible siblings at this depth (for aria-setsize). */
  siblingCount: number;
  /** 1-based position among siblings at this depth (for aria-posinset). */
  siblingIndex: number;
}

/** Read-only state surfaced to slots and the imperative ref. */
export interface FileTreeState {
  expandedIds: ReadonlySet<string>;
  selectedIds: ReadonlySet<string>;
  focusedId: string | null;
  renamingId: string | null;
  loadingFolderIds: ReadonlySet<string>;
}

/** Imperative actions exposed to slots and the imperative ref. */
export interface FileTreeActions {
  expand: (id: string) => void;
  collapse: (id: string) => void;
  toggleExpand: (id: string) => void;
  expandAll: () => void;
  collapseAll: () => void;
  select: (idOrIds: string | string[]) => void;
  clearSelection: () => void;
  focusNode: (id: string) => void;
  startRename: (id: string) => void;
  cancelRename: () => void;
  triggerCreate: (parentId: string | null, type: FsNodeType) => void;
  triggerDelete: (ids: string[]) => void;
  refresh: (nodeId?: string | null) => void;
}

export interface FileTreeHandle {
  state: FileTreeState;
  actions: FileTreeActions;
}

// ─── Callback arg shapes (object-shape per F-cross-12) ──────────────────────

export interface FileTreeOpenArgs {
  node: FsNode;
}
export interface FileTreeCreateArgs {
  parentId: string | null;
  type: FsNodeType;
}
export interface FileTreeRenameArgs {
  id: string;
  node: FsNode;
  nextName: string;
}
export interface FileTreeDeleteArgs {
  ids: string[];
}
export interface FileTreeMoveArgs {
  ids: string[];
  targetId: string | null;
  position: FileTreeDropPosition;
}
export interface FileTreeRefreshArgs {
  nodeId: string | null;
}
export interface FileTreeExternalDropArgs {
  files: File[];
  targetId: string | null;
}
export interface FileTreeLoadChildrenArgs {
  nodeId: string;
  node: FsNode;
}
export interface FileTreeSelectionChangeArgs {
  ids: Set<string>;
}
export interface FileTreeExpandedChangeArgs {
  ids: Set<string>;
}
export interface FileTreeValidateRenameArgs {
  node: FsNode;
  nextName: string;
}
export interface FileTreeIconForNodeArgs {
  node: FsNode;
}

// ─── Default labels (full set; consumers override partially via `labels` prop) ─

export interface FileTreeLabels {
  title: string;
  newFile: string;
  newFolder: string;
  refresh: string;
  collapseAll: string;
  contextOpen: string;
  contextNewFile: string;
  contextNewFolder: string;
  contextRename: string;
  contextDelete: string;
  contextRefresh: string;
  deleteConfirmTitle: string;
  deleteConfirmDescription: string;
  deleteConfirmAction: string;
  deleteConfirmCancel: string;
  emptyTitle: string;
  loading: string;
  externalDropOverlay: string;
  nodeCount: string;
  loadError: string;
  retry: string;
}

// ─── Slot contexts ──────────────────────────────────────────────────────────

export interface FileTreeHeaderContext {
  state: FileTreeState;
  actions: FileTreeActions;
  totalCount: number;
  visibleCount: number;
  showNewFile: boolean;
  showNewFolder: boolean;
  showRefresh: boolean;
  showCollapseAll: boolean;
  title?: string;
  labels: FileTreeLabels;
}

export type FileTreeContextMenuItemId =
  | "open"
  | "new-file"
  | "new-folder"
  | "rename"
  | "delete"
  | "refresh";

export interface FileTreeContextMenuItem {
  id: FileTreeContextMenuItemId;
  label: string;
  onSelect: () => void;
  disabled?: boolean;
  destructive?: boolean;
  icon?: ReactNode;
}

export interface FileTreeContextMenuContext {
  state: FileTreeState;
  actions: FileTreeActions;
  /** The node under the right-click target. `null` when right-clicking empty whitespace. */
  node: FsNode | null;
  defaultActions: FileTreeContextMenuItem[];
  position: { x: number; y: number };
  labels: FileTreeLabels;
}

export interface FileTreeEmptyContext {
  actions: FileTreeActions;
  showNewFile: boolean;
  showNewFolder: boolean;
  labels: FileTreeLabels;
}

export interface FileTreeRowRenderArgs {
  row: FileTreeRow;
  defaultRow: ReactNode;
}

export interface FileTreeDeleteConfirmContext {
  ids: string[];
  nodes: FsNode[];
  onConfirm: () => void;
  onCancel: () => void;
  labels: FileTreeLabels;
}

// ─── Top-level props ────────────────────────────────────────────────────────

export interface FileTreeProps {
  // Data
  nodes: FsNode[];
  loading?: boolean;

  // Selection
  selectionMode?: FileTreeSelectionMode;
  selectedIds?: Set<string>;
  defaultSelectedIds?: Set<string>;
  onSelectedChange?: (args: FileTreeSelectionChangeArgs) => void;

  // Expansion
  expandedIds?: Set<string>;
  defaultExpandedIds?: Set<string>;
  onExpandedChange?: (args: FileTreeExpandedChangeArgs) => void;

  // Lazy loading
  onLoadChildren?: (args: FileTreeLoadChildrenArgs) => Promise<FsNode[]>;

  // Operations
  onOpen?: (args: FileTreeOpenArgs) => void;
  onCreate?: (args: FileTreeCreateArgs) => void;
  onRename?: (args: FileTreeRenameArgs) => void;
  onDelete?: (args: FileTreeDeleteArgs) => void;
  onMove?: (args: FileTreeMoveArgs) => void;
  onRefresh?: (args: FileTreeRefreshArgs) => void;
  onExternalDrop?: (args: FileTreeExternalDropArgs) => void;
  validateRename?: (args: FileTreeValidateRenameArgs) => string | null;

  // Rendering
  iconForNode?: (args: FileTreeIconForNodeArgs) => ReactNode;
  renderRow?: (args: FileTreeRowRenderArgs) => ReactNode;
  renderHeader?: (ctx: FileTreeHeaderContext) => ReactNode;
  renderContextMenu?: (ctx: FileTreeContextMenuContext) => ReactNode;
  renderEmpty?: (ctx: FileTreeEmptyContext) => ReactNode;
  renderLoading?: () => ReactNode;
  renderDeleteConfirm?: (ctx: FileTreeDeleteConfirmContext) => ReactNode;

  // Header config
  header?: boolean;
  title?: string;
  showNewFile?: boolean;
  showNewFolder?: boolean;
  showRefresh?: boolean;
  showCollapseAll?: boolean;

  // Context-menu config
  contextMenu?: boolean;
  contextMenuActions?: {
    open?: boolean;
    newFile?: boolean;
    newFolder?: boolean;
    rename?: boolean;
    delete?: boolean;
    refresh?: boolean;
  };

  // Behavior
  showHidden?: boolean;
  isHidden?: (node: FsNode) => boolean;
  sortNodes?: ((a: FsNode, b: FsNode) => number) | false;
  indentGuides?: boolean;
  rowHeight?: number;
  indent?: number;

  // Confirmation
  confirmDelete?: boolean;

  // DnD
  enableInternalDrag?: boolean;
  enableExternalDrop?: boolean;

  // Virtualization
  virtualize?: FileTreeVirtualizeMode;
  virtualizeThreshold?: number;

  // Polymorphic
  className?: string;
  style?: CSSProperties;

  // Imperative handle
  ref?: Ref<FileTreeHandle>;

  // i18n labels
  labels?: Partial<FileTreeLabels>;
}

/** Default labels — exported so consumers can build complete label objects. */
export const DEFAULT_FILE_TREE_LABELS: FileTreeLabels = {
  title: "Files",
  newFile: "New File",
  newFolder: "New Folder",
  refresh: "Refresh",
  collapseAll: "Collapse All",
  contextOpen: "Open",
  contextNewFile: "New File",
  contextNewFolder: "New Folder",
  contextRename: "Rename",
  contextDelete: "Delete",
  contextRefresh: "Refresh",
  deleteConfirmTitle: "Delete items?",
  deleteConfirmDescription: "This action cannot be undone.",
  deleteConfirmAction: "Delete",
  deleteConfirmCancel: "Cancel",
  emptyTitle: "No items",
  loading: "Loading…",
  externalDropOverlay: "Drop files here",
  nodeCount: "items",
  loadError: "Failed to load",
  retry: "Retry",
};

"use client";

import { createContext, useContext } from "react";
import type {
  FileTreeActions,
  FileTreeLabels,
  FileTreeRow,
  FileTreeState,
} from "../types";

export interface FileTreeContextValue {
  state: FileTreeState;
  actions: FileTreeActions;
  rows: FileTreeRow[];
  totalCount: number;
  visibleCount: number;
  /** Header config (read by standalone parts). */
  showNewFile: boolean;
  showNewFolder: boolean;
  showRefresh: boolean;
  showCollapseAll: boolean;
  title?: string;
  labels: FileTreeLabels;
}

export const FileTreeContext = createContext<FileTreeContextValue | null>(null);

/**
 * Public consumer hook. Exposes state, actions, and header-config for
 * consumers building a custom header inside `renderHeader` or composing
 * standalone parts.
 *
 * Throws if called outside `<FileTree>`.
 */
export function useFileTree(): FileTreeContextValue {
  const ctx = useContext(FileTreeContext);
  if (!ctx) {
    throw new Error("useFileTree() must be called inside <FileTree>");
  }
  return ctx;
}

"use client";

import { useCallback, useMemo, useRef, useState } from "react";
import type {
  FileTreeActions,
  FileTreeExpandedChangeArgs,
  FileTreeSelectionChangeArgs,
  FileTreeSelectionMode,
  FileTreeState,
  FsNode,
  FsNodeType,
} from "../types";
import {
  countAllNodes,
  deriveRootExpandedIds,
  indexNodes,
} from "../lib/tree-utils";

interface UseTreeStateArgs {
  nodes: FsNode[];
  selectionMode: FileTreeSelectionMode;
  selectedIds: Set<string> | undefined;
  defaultSelectedIds: Set<string> | undefined;
  onSelectedChange?: (args: FileTreeSelectionChangeArgs) => void;
  expandedIds: Set<string> | undefined;
  defaultExpandedIds: Set<string> | undefined;
  onExpandedChange?: (args: FileTreeExpandedChangeArgs) => void;
  onCreate?: (args: { parentId: string | null; type: FsNodeType }) => void;
  onDelete?: (args: { ids: string[] }) => void;
  onRefresh?: (args: { nodeId: string | null }) => void;
  confirmDelete: boolean;
  /**
   * Callback used by `triggerDelete` when `confirmDelete` is `true`. The
   * orchestrator implements this and shows the AlertDialog. When the dialog
   * confirms, it calls `onDelete` directly. When `confirmDelete` is `false`,
   * `triggerDelete` skips this and fires `onDelete` immediately.
   */
  requestDeleteConfirmation: (ids: string[]) => void;
}

export interface UseTreeStateResult {
  state: FileTreeState;
  actions: FileTreeActions;
  totalCount: number;
  /** Read the current selection anchor (use only inside event handlers, not during render). */
  getSelectionAnchorId: () => string | null;
  setSelectionAnchorId: (id: string | null) => void;
  /** Internal write helpers used by other hooks. */
  setLoadingFolderIds: (next: Set<string>) => void;
}

export function useTreeState(args: UseTreeStateArgs): UseTreeStateResult {
  const {
    nodes,
    selectionMode,
    selectedIds: controlledSelected,
    defaultSelectedIds,
    onSelectedChange,
    expandedIds: controlledExpanded,
    defaultExpandedIds,
    onExpandedChange,
    onCreate,
    onDelete,
    onRefresh,
    confirmDelete,
    requestDeleteConfirmation,
  } = args;

  // Initial uncontrolled state. `useState`'s lazy initializer keeps the
  // root-derive call O(roots) on first render only.
  const [internalExpanded, setInternalExpanded] = useState<Set<string>>(
    () => defaultExpandedIds ?? deriveRootExpandedIds(nodes),
  );
  const [internalSelected, setInternalSelected] = useState<Set<string>>(
    () => defaultSelectedIds ?? new Set(),
  );
  const [focusedId, setFocusedId] = useState<string | null>(null);
  const [renamingId, setRenamingId] = useState<string | null>(null);
  const [loadingFolderIds, setLoadingFolderIdsRaw] = useState<Set<string>>(
    () => new Set(),
  );
  const selectionAnchorRef = useRef<string | null>(null);

  const expandedIds = controlledExpanded ?? internalExpanded;
  const selectedIds = controlledSelected ?? internalSelected;

  const setExpanded = useCallback(
    (next: Set<string>) => {
      if (controlledExpanded === undefined) setInternalExpanded(next);
      onExpandedChange?.({ ids: next });
    },
    [controlledExpanded, onExpandedChange],
  );

  const setSelected = useCallback(
    (next: Set<string>) => {
      if (controlledSelected === undefined) setInternalSelected(next);
      onSelectedChange?.({ ids: next });
    },
    [controlledSelected, onSelectedChange],
  );

  const expand = useCallback(
    (id: string) => {
      if (expandedIds.has(id)) return;
      const next = new Set(expandedIds);
      next.add(id);
      setExpanded(next);
    },
    [expandedIds, setExpanded],
  );

  const collapse = useCallback(
    (id: string) => {
      if (!expandedIds.has(id)) return;
      const next = new Set(expandedIds);
      next.delete(id);
      setExpanded(next);
    },
    [expandedIds, setExpanded],
  );

  const toggleExpand = useCallback(
    (id: string) => {
      const next = new Set(expandedIds);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      setExpanded(next);
    },
    [expandedIds, setExpanded],
  );

  const expandAll = useCallback(() => {
    const next = new Set<string>();
    const walk = (list: FsNode[]) => {
      for (const node of list) {
        if (node.type === "folder") next.add(node.id);
        if (node.children) walk(node.children);
      }
    };
    walk(nodes);
    setExpanded(next);
  }, [nodes, setExpanded]);

  const collapseAll = useCallback(() => {
    setExpanded(new Set());
  }, [setExpanded]);

  const select = useCallback(
    (idOrIds: string | string[]) => {
      const ids = Array.isArray(idOrIds) ? idOrIds : [idOrIds];
      if (selectionMode === "single") {
        setSelected(new Set(ids.slice(0, 1)));
      } else {
        setSelected(new Set(ids));
      }
      if (ids.length > 0) selectionAnchorRef.current = ids[0];
    },
    [selectionMode, setSelected],
  );

  const clearSelection = useCallback(() => {
    setSelected(new Set());
    selectionAnchorRef.current = null;
  }, [setSelected]);

  const focusNode = useCallback((id: string) => {
    setFocusedId(id);
  }, []);

  const startRename = useCallback((id: string) => {
    setRenamingId(id);
  }, []);

  const cancelRename = useCallback(() => {
    setRenamingId(null);
  }, []);

  const triggerCreate = useCallback(
    (parentId: string | null, type: FsNodeType) => {
      onCreate?.({ parentId, type });
    },
    [onCreate],
  );

  const triggerDelete = useCallback(
    (ids: string[]) => {
      if (ids.length === 0) return;
      if (confirmDelete) {
        requestDeleteConfirmation(ids);
        return;
      }
      onDelete?.({ ids });
    },
    [confirmDelete, requestDeleteConfirmation, onDelete],
  );

  const refresh = useCallback(
    (nodeId: string | null = null) => {
      onRefresh?.({ nodeId });
    },
    [onRefresh],
  );

  const setSelectionAnchorId = useCallback((id: string | null) => {
    selectionAnchorRef.current = id;
  }, []);

  const setLoadingFolderIds = useCallback((next: Set<string>) => {
    setLoadingFolderIdsRaw(next);
  }, []);

  const totalCount = useMemo(() => countAllNodes(nodes), [nodes]);

  // Drop selection ids that no longer reference real nodes
  const sanitizedSelectedIds = useMemo(() => {
    if (selectedIds.size === 0) return selectedIds;
    const idx = indexNodes(nodes);
    let dirty = false;
    const next = new Set<string>();
    for (const id of selectedIds) {
      if (idx.has(id)) next.add(id);
      else dirty = true;
    }
    return dirty ? next : selectedIds;
  }, [nodes, selectedIds]);

  const state: FileTreeState = useMemo(
    () => ({
      expandedIds,
      selectedIds: sanitizedSelectedIds,
      focusedId,
      renamingId,
      loadingFolderIds,
    }),
    [
      expandedIds,
      sanitizedSelectedIds,
      focusedId,
      renamingId,
      loadingFolderIds,
    ],
  );

  const actions: FileTreeActions = useMemo(
    () => ({
      expand,
      collapse,
      toggleExpand,
      expandAll,
      collapseAll,
      select,
      clearSelection,
      focusNode,
      startRename,
      cancelRename,
      triggerCreate,
      triggerDelete,
      refresh,
    }),
    [
      expand,
      collapse,
      toggleExpand,
      expandAll,
      collapseAll,
      select,
      clearSelection,
      focusNode,
      startRename,
      cancelRename,
      triggerCreate,
      triggerDelete,
      refresh,
    ],
  );

  const getSelectionAnchorId = useCallback(
    () => selectionAnchorRef.current,
    [],
  );

  return {
    state,
    actions,
    totalCount,
    getSelectionAnchorId,
    setSelectionAnchorId,
    setLoadingFolderIds,
  };
}

"use client";

import { useMemo } from "react";
import type { FileTreeRow, FsNode } from "../types";
import { defaultSort } from "../lib/tree-utils";

interface UseTreeFlattenArgs {
  nodes: FsNode[];
  expandedIds: ReadonlySet<string>;
  selectedIds: ReadonlySet<string>;
  focusedId: string | null;
  loadingFolderIds: ReadonlySet<string>;
  showHidden: boolean;
  isHidden?: (node: FsNode) => boolean;
  sortNodes: ((a: FsNode, b: FsNode) => number) | false | undefined;
}

const defaultIsHidden = (node: FsNode) => node.name.startsWith(".");

/**
 * Walks the tree, applies sort + visibility, returns the visible-row array
 * the virtualizer (and naive renderer) consume.
 */
export function useTreeFlatten(args: UseTreeFlattenArgs): FileTreeRow[] {
  const {
    nodes,
    expandedIds,
    selectedIds,
    focusedId,
    loadingFolderIds,
    showHidden,
    isHidden,
    sortNodes,
  } = args;

  return useMemo(() => {
    const rows: FileTreeRow[] = [];
    const hiddenFn = isHidden ?? defaultIsHidden;
    const sorter = sortNodes === false ? null : sortNodes ?? defaultSort;

    const walk = (list: FsNode[], depth: number) => {
      const filtered = showHidden
        ? list
        : list.filter((node) => !hiddenFn(node));
      const sorted = sorter ? [...filtered].sort(sorter) : filtered;
      const siblingCount = sorted.length;
      sorted.forEach((node, siblingIdx) => {
        const isFolder = node.type === "folder";
        const expanded = isFolder && expandedIds.has(node.id);
        const childrenLoaded = isFolder && node.children !== undefined;
        const hasChildren =
          isFolder &&
          (node.children === undefined || (node.children?.length ?? 0) > 0);
        rows.push({
          node,
          depth,
          expanded,
          selected: selectedIds.has(node.id),
          focused: focusedId === node.id,
          hasChildren,
          childrenLoaded,
          loadingChildren: loadingFolderIds.has(node.id),
          index: rows.length,
          siblingCount,
          siblingIndex: siblingIdx + 1,
        });
        if (expanded && node.children?.length) {
          walk(node.children, depth + 1);
        }
        // Empty (`children: []`) folders render an "(empty)" placeholder row
        // inline; the row component handles that, not the flatten.
      });
    };
    walk(nodes, 0);
    return rows;
  }, [
    nodes,
    expandedIds,
    selectedIds,
    focusedId,
    loadingFolderIds,
    showHidden,
    isHidden,
    sortNodes,
  ]);
}

"use client";

import { useCallback } from "react";
import type { KeyboardEvent } from "react";
import type {
  FileTreeActions,
  FileTreeOpenArgs,
  FileTreeRow,
  FileTreeSelectionMode,
} from "../types";

interface UseTreeKeyboardArgs {
  rows: FileTreeRow[];
  focusedId: string | null;
  renamingId: string | null;
  selectionMode: FileTreeSelectionMode;
  selectedIds: ReadonlySet<string>;
  actions: FileTreeActions;
  onOpen?: (args: FileTreeOpenArgs) => void;
}

export interface UseTreeKeyboardResult {
  onKeyDown: (e: KeyboardEvent<HTMLDivElement>) => void;
}

const META_KEYS = ["INPUT", "TEXTAREA", "SELECT"];

export function useTreeKeyboard(
  args: UseTreeKeyboardArgs,
): UseTreeKeyboardResult {
  const {
    rows,
    focusedId,
    renamingId,
    selectionMode,
    selectedIds,
    actions,
    onOpen,
  } = args;

  const onKeyDown = useCallback(
    (e: KeyboardEvent<HTMLDivElement>) => {
      // If user is typing in the rename input or any other text field, bail.
      const target = e.target as HTMLElement | null;
      if (target && META_KEYS.includes(target.tagName)) return;
      // If a rename is active anywhere, the rename input intercepts its own keys.
      // Anything else here just passes through.
      if (renamingId) return;

      const isMod = e.metaKey || e.ctrlKey;

      // Find current row index by focusedId
      const idx = rows.findIndex((r) => r.node.id === focusedId);
      const noFocus = idx === -1;

      switch (e.key) {
        case "ArrowDown": {
          e.preventDefault();
          const next = noFocus ? 0 : Math.min(rows.length - 1, idx + 1);
          if (rows[next]) actions.focusNode(rows[next].node.id);
          return;
        }
        case "ArrowUp": {
          e.preventDefault();
          const next = noFocus ? 0 : Math.max(0, idx - 1);
          if (rows[next]) actions.focusNode(rows[next].node.id);
          return;
        }
        case "ArrowRight": {
          e.preventDefault();
          if (noFocus) {
            if (rows[0]) actions.focusNode(rows[0].node.id);
            return;
          }
          const row = rows[idx];
          if (row.node.type === "folder" && row.hasChildren) {
            if (row.expanded) {
              // move to first child
              const childRow = rows[idx + 1];
              if (childRow && childRow.depth > row.depth) {
                actions.focusNode(childRow.node.id);
              }
            } else {
              actions.expand(row.node.id);
            }
          }
          return;
        }
        case "ArrowLeft": {
          e.preventDefault();
          if (noFocus) {
            if (rows[0]) actions.focusNode(rows[0].node.id);
            return;
          }
          const row = rows[idx];
          if (row.node.type === "folder" && row.expanded) {
            actions.collapse(row.node.id);
          } else {
            // move to parent
            for (let i = idx - 1; i >= 0; i--) {
              if (rows[i].depth < row.depth) {
                actions.focusNode(rows[i].node.id);
                break;
              }
            }
          }
          return;
        }
        case "Home": {
          e.preventDefault();
          if (rows[0]) actions.focusNode(rows[0].node.id);
          return;
        }
        case "End": {
          e.preventDefault();
          const last = rows[rows.length - 1];
          if (last) actions.focusNode(last.node.id);
          return;
        }
        case "Enter": {
          if (noFocus) return;
          e.preventDefault();
          const row = rows[idx];
          if (row.node.type === "folder") {
            actions.toggleExpand(row.node.id);
          } else {
            onOpen?.({ node: row.node });
          }
          return;
        }
        case " ": // Space
        case "Spacebar": {
          if (noFocus) return;
          e.preventDefault();
          const row = rows[idx];
          if (selectionMode === "multi") {
            const next = new Set(selectedIds);
            if (next.has(row.node.id)) next.delete(row.node.id);
            else next.add(row.node.id);
            actions.select(Array.from(next));
          } else {
            actions.select(row.node.id);
          }
          return;
        }
        case "F2": {
          if (noFocus) return;
          e.preventDefault();
          actions.startRename(rows[idx].node.id);
          return;
        }
        case "Delete":
        case "Backspace": {
          if (selectedIds.size === 0) return;
          e.preventDefault();
          actions.triggerDelete(Array.from(selectedIds));
          return;
        }
        case "Escape": {
          if (selectedIds.size > 0) {
            e.preventDefault();
            actions.clearSelection();
          }
          return;
        }
        case "a":
        case "A": {
          if (!isMod) return;
          if (selectionMode !== "multi") return;
          e.preventDefault();
          actions.select(rows.map((r) => r.node.id));
          return;
        }
        default:
          return;
      }
    },
    [rows, focusedId, renamingId, selectionMode, selectedIds, actions, onOpen],
  );

  return { onKeyDown };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import type { DragEvent } from "react";
import type { DragOverState } from "../parts/file-tree-row-list";
import type {
  FileTreeDropPosition,
  FileTreeMoveArgs,
  FileTreeRow,
  FsNode,
} from "../types";
import { isLegalDrop } from "../lib/validation";
import { indexNodes } from "../lib/tree-utils";

const INTERNAL_MIME = "application/x-ilinxa-file-tree";

interface UseTreeDragArgs {
  nodes: FsNode[];
  enableInternalDrag: boolean;
  enableExternalDrop: boolean;
  selectedIds: ReadonlySet<string>;
  selectionMode: "single" | "multi";
  onMove?: (args: FileTreeMoveArgs) => void;
  onExternalDrop?: (args: { files: File[]; targetId: string | null }) => void;
  /** Replace selection with a single id (used at drag-start when source isn't selected). */
  selectIds: (idOrIds: string | string[]) => void;
}

export interface UseTreeDragResult {
  dragOver: DragOverState | null;
  isExternalDragging: boolean;
  isInternalDragging: boolean;
  // Row-level handlers
  onRowDragStart: (e: DragEvent, row: FileTreeRow) => void;
  onRowDragOver: (e: DragEvent, row: FileTreeRow) => void;
  onRowDragLeave: (e: DragEvent, row: FileTreeRow) => void;
  onRowDrop: (e: DragEvent, row: FileTreeRow) => void;
  onRowDragEnd: (e: DragEvent, row: FileTreeRow) => void;
  // Container-level handlers (root + scroll area)
  onContainerDragEnter: (e: DragEvent) => void;
  onContainerDragOver: (e: DragEvent) => void;
  onContainerDragLeave: (e: DragEvent) => void;
  onContainerDrop: (e: DragEvent) => void;
  /** Map of `clientY` → scroll-direction; only active during drag near edges. */
  startAutoScroll: (
    container: HTMLElement | null,
    clientY: number,
  ) => void;
  stopAutoScroll: () => void;
}

const AUTO_SCROLL_EDGE_PX = 24;
const AUTO_SCROLL_PX_PER_FRAME = 4;

export function useTreeDrag(args: UseTreeDragArgs): UseTreeDragResult {
  const {
    nodes,
    enableInternalDrag,
    enableExternalDrop,
    selectedIds,
    selectionMode,
    onMove,
    onExternalDrop,
    selectIds,
  } = args;

  const [dragOver, setDragOver] = useState<DragOverState | null>(null);
  const [isExternalDragging, setIsExternalDragging] = useState(false);
  const isInternalDraggingRef = useRef(false);
  const [isInternalDragging, setIsInternalDragging] = useState(false);
  // Track external-drag enter/leave with a refcount (events fire per nested element)
  const externalEnterCountRef = useRef(0);
  const dragSourceIdsRef = useRef<string[]>([]);
  const autoScrollRef = useRef<{
    container: HTMLElement | null;
    direction: number;
    raf: number | null;
  }>({ container: null, direction: 0, raf: null });

  const stopAutoScroll = useCallback(() => {
    const ref = autoScrollRef.current;
    if (ref.raf !== null) {
      cancelAnimationFrame(ref.raf);
      ref.raf = null;
    }
    ref.direction = 0;
    ref.container = null;
  }, []);

  const startAutoScroll = useCallback(
    (container: HTMLElement | null, clientY: number) => {
      if (!container) return;
      const rect = container.getBoundingClientRect();
      let dir = 0;
      if (clientY - rect.top < AUTO_SCROLL_EDGE_PX) dir = -1;
      else if (rect.bottom - clientY < AUTO_SCROLL_EDGE_PX) dir = 1;
      const ref = autoScrollRef.current;
      ref.container = container;
      if (dir !== ref.direction) {
        ref.direction = dir;
        if (ref.raf !== null) {
          cancelAnimationFrame(ref.raf);
          ref.raf = null;
        }
        if (dir !== 0) {
          const tick = () => {
            const r = autoScrollRef.current;
            if (r.container && r.direction !== 0) {
              r.container.scrollTop +=
                r.direction * AUTO_SCROLL_PX_PER_FRAME;
              r.raf = requestAnimationFrame(tick);
            } else {
              r.raf = null;
            }
          };
          ref.raf = requestAnimationFrame(tick);
        }
      }
    },
    [],
  );

  // Cleanup on unmount
  useEffect(() => {
    return () => stopAutoScroll();
  }, [stopAutoScroll]);

  const computePosition = (
    e: DragEvent,
    row: FileTreeRow,
  ): FileTreeDropPosition => {
    const target = e.currentTarget as HTMLElement;
    const rect = target.getBoundingClientRect();
    const y = e.clientY - rect.top;
    const h = rect.height;
    if (row.node.type === "folder") {
      // three zones
      if (y < h * 0.25) return "before";
      if (y > h * 0.75) return "after";
      return "inside";
    }
    // file: two zones
    return y < h * 0.5 ? "before" : "after";
  };

  const onRowDragStart = useCallback(
    (e: DragEvent, row: FileTreeRow) => {
      if (!enableInternalDrag) return;
      // Ensure dragged node is part of selection. If it's already in
      // multi-select, drag the whole selection. Otherwise replace selection.
      let ids: string[];
      if (selectionMode === "multi" && selectedIds.has(row.node.id)) {
        ids = Array.from(selectedIds);
      } else {
        ids = [row.node.id];
        selectIds(row.node.id);
      }
      dragSourceIdsRef.current = ids;
      isInternalDraggingRef.current = true;
      setIsInternalDragging(true);
      try {
        e.dataTransfer.effectAllowed = "move";
        // Write a sentinel value so we can recognize own drag in dragenter
        e.dataTransfer.setData(INTERNAL_MIME, "1");
      } catch {
        // some envs throw on synthetic events
      }
    },
    [enableInternalDrag, selectionMode, selectedIds, selectIds],
  );

  const onRowDragEnd = useCallback(() => {
    isInternalDraggingRef.current = false;
    setIsInternalDragging(false);
    dragSourceIdsRef.current = [];
    setDragOver(null);
    stopAutoScroll();
  }, [stopAutoScroll]);

  const onRowDragOver = useCallback(
    (e: DragEvent, row: FileTreeRow) => {
      // External-drag is handled by container handlers; row-level is internal-only.
      if (!isInternalDraggingRef.current) return;
      e.preventDefault();
      const position = computePosition(e, row);
      // For position 'before'/'after', cycle check uses target's parent
      const idx = indexNodes(nodes);
      const valid = isLegalDrop({
        srcIds: dragSourceIdsRef.current,
        targetId: row.node.id,
        position,
        index: idx,
      });
      e.dataTransfer.dropEffect = valid ? "move" : "none";
      setDragOver({ rowId: row.node.id, position, valid });
      // auto-scroll near edges
      const scroller = (e.currentTarget as HTMLElement).closest(
        "[data-file-tree-scroller]",
      ) as HTMLElement | null;
      startAutoScroll(scroller, e.clientY);
    },
    [nodes, startAutoScroll],
  );

  const onRowDragLeave = useCallback(
    (_e: DragEvent, row: FileTreeRow) => {
      // Only clear if leaving the current target
      setDragOver((prev) => (prev?.rowId === row.node.id ? null : prev));
    },
    [],
  );

  const onRowDrop = useCallback(
    (e: DragEvent, row: FileTreeRow) => {
      if (!isInternalDraggingRef.current) return;
      e.preventDefault();
      const position = computePosition(e, row);
      const idx = indexNodes(nodes);
      const ids = dragSourceIdsRef.current;
      const valid = isLegalDrop({
        srcIds: ids,
        targetId: row.node.id,
        position,
        index: idx,
      });
      if (valid && onMove) {
        const targetId =
          position === "inside" ? row.node.id : (row.node.parentId ?? null);
        onMove({ ids, targetId, position });
      }
      setDragOver(null);
      stopAutoScroll();
      isInternalDraggingRef.current = false;
      setIsInternalDragging(false);
      dragSourceIdsRef.current = [];
    },
    [nodes, onMove, stopAutoScroll],
  );

  // ── External-drop (OS files) handlers on the container ────────────────────

  const hasFiles = (e: DragEvent) =>
    Array.from(e.dataTransfer.types).includes("Files");

  const onContainerDragEnter = useCallback(
    (e: DragEvent) => {
      if (!enableExternalDrop) return;
      if (!hasFiles(e)) return;
      externalEnterCountRef.current += 1;
      setIsExternalDragging(true);
    },
    [enableExternalDrop],
  );

  const onContainerDragOver = useCallback(
    (e: DragEvent) => {
      if (!enableExternalDrop) return;
      if (!hasFiles(e)) return;
      e.preventDefault();
      e.dataTransfer.dropEffect = "copy";
    },
    [enableExternalDrop],
  );

  const onContainerDragLeave = useCallback(
    (e: DragEvent) => {
      if (!enableExternalDrop) return;
      if (!hasFiles(e)) return;
      externalEnterCountRef.current = Math.max(
        0,
        externalEnterCountRef.current - 1,
      );
      if (externalEnterCountRef.current === 0) {
        setIsExternalDragging(false);
      }
    },
    [enableExternalDrop],
  );

  const onContainerDrop = useCallback(
    (e: DragEvent) => {
      if (!enableExternalDrop) return;
      if (!hasFiles(e)) return;
      e.preventDefault();
      externalEnterCountRef.current = 0;
      setIsExternalDragging(false);
      const target = e.target as HTMLElement | null;
      const rowEl = target?.closest("[data-row-id]") as HTMLElement | null;
      const rowId = rowEl?.getAttribute("data-row-id") ?? null;
      const idx = indexNodes(nodes);
      let targetId: string | null = null;
      if (rowId) {
        const node = idx.get(rowId);
        if (node) {
          targetId = node.type === "folder" ? rowId : (node.parentId ?? null);
        }
      }
      const files = Array.from(e.dataTransfer.files ?? []);
      if (files.length > 0) {
        onExternalDrop?.({ files, targetId });
      }
    },
    [enableExternalDrop, nodes, onExternalDrop],
  );

  return {
    dragOver,
    isExternalDragging,
    isInternalDragging,
    onRowDragStart,
    onRowDragOver,
    onRowDragLeave,
    onRowDrop,
    onRowDragEnd,
    onContainerDragEnter,
    onContainerDragOver,
    onContainerDragLeave,
    onContainerDrop,
    startAutoScroll,
    stopAutoScroll,
  };
}

"use client";

import { useVirtualizer } from "@tanstack/react-virtual";
import type { RefObject } from "react";
import type { FileTreeRow, FileTreeVirtualizeMode } from "../types";

interface UseTreeVirtualArgs {
  rows: FileTreeRow[];
  scrollRef: RefObject<HTMLDivElement | null>;
  mode: FileTreeVirtualizeMode;
  threshold: number;
  rowHeight: number;
}

export interface UseTreeVirtualResult {
  /** `true` when virtualization is active. */
  active: boolean;
  /** Virtualizer instance — only meaningful when `active`. */
  virtualizer: ReturnType<typeof useVirtualizer<HTMLDivElement, HTMLDivElement>>;
}

export function useTreeVirtual(
  args: UseTreeVirtualArgs,
): UseTreeVirtualResult {
  const { rows, scrollRef, mode, threshold, rowHeight } = args;
  const active =
    mode === "always" || (mode === "auto" && rows.length >= threshold);

  const virtualizer = useVirtualizer<HTMLDivElement, HTMLDivElement>({
    count: rows.length,
    getScrollElement: () => scrollRef.current,
    estimateSize: () => rowHeight,
    overscan: 8,
    enabled: active,
  });

  return { active, virtualizer };
}

"use client";

import { useCallback, useRef, useState } from "react";
import type { FileTreeLoadChildrenArgs, FsNode } from "../types";

interface UseLazyLoadArgs {
  onLoadChildren?: (args: FileTreeLoadChildrenArgs) => Promise<FsNode[]>;
  setLoadingFolderIds: (next: Set<string>) => void;
}

export interface UseLazyLoadResult {
  /** Per-folder error message, if the most recent load rejected. */
  errors: ReadonlyMap<string, string>;
  /** Trigger a load. Bumps `loadingFolderIds`, resolves cleanly, stores errors. */
  load: (node: FsNode) => Promise<void>;
  /** Clear an error for retry. */
  clearError: (nodeId: string) => void;
}

/**
 * Manages async-children loading state. Does NOT merge resolved children
 * into the tree — that's the consumer's job (we expose `mergeLoadedChildren`
 * helper for that). Tracks loading + error state per folder id.
 */
export function useLazyLoad(args: UseLazyLoadArgs): UseLazyLoadResult {
  const { onLoadChildren, setLoadingFolderIds } = args;
  const loadingRef = useRef<Set<string>>(new Set());
  const [errors, setErrors] = useState<Map<string, string>>(() => new Map());

  const setLoading = useCallback(
    (mutator: (prev: Set<string>) => Set<string>) => {
      const next = mutator(new Set(loadingRef.current));
      loadingRef.current = next;
      setLoadingFolderIds(next);
    },
    [setLoadingFolderIds],
  );

  const load = useCallback(
    async (node: FsNode) => {
      if (!onLoadChildren) return;
      if (loadingRef.current.has(node.id)) return;
      setLoading((prev) => {
        prev.add(node.id);
        return prev;
      });
      // Clear any previous error for this id
      setErrors((prev) => {
        if (!prev.has(node.id)) return prev;
        const next = new Map(prev);
        next.delete(node.id);
        return next;
      });
      try {
        await onLoadChildren({ nodeId: node.id, node });
      } catch (err) {
        const msg = err instanceof Error ? err.message : "Failed to load";
        setErrors((prev) => {
          const next = new Map(prev);
          next.set(node.id, msg);
          return next;
        });
      } finally {
        setLoading((prev) => {
          prev.delete(node.id);
          return prev;
        });
      }
    },
    [onLoadChildren, setLoading],
  );

  const clearError = useCallback((nodeId: string) => {
    setErrors((prev) => {
      if (!prev.has(nodeId)) return prev;
      const next = new Map(prev);
      next.delete(nodeId);
      return next;
    });
  }, []);

  return { errors, load, clearError };
}

import type { ReactNode } from "react";
import {
  File,
  FileArchive,
  FileAudio,
  FileCode,
  FileCode2,
  FileImage,
  FileJson,
  FileText,
  FileVideo,
  Folder,
  FolderOpen,
} from "lucide-react";

import type { FsNode } from "../types";

/**
 * Mapping of common file-extension categories to their default Lucide icon.
 * Order of definition matters only for documentation; lookup is by the
 * extension string itself.
 */
const EXT_TO_ICON: Record<string, typeof File> = {
  // Code (general)
  ts: FileCode,
  tsx: FileCode,
  js: FileCode,
  jsx: FileCode,
  mjs: FileCode,
  cjs: FileCode,
  py: FileCode,
  rb: FileCode,
  go: FileCode,
  rs: FileCode,
  java: FileCode,
  kt: FileCode,
  swift: FileCode,
  cpp: FileCode,
  c: FileCode,
  h: FileCode,
  cs: FileCode,
  php: FileCode,
  lua: FileCode,
  // CSS family
  css: FileCode,
  scss: FileCode,
  sass: FileCode,
  less: FileCode,
  // Markup
  html: FileCode2,
  htm: FileCode2,
  xml: FileCode2,
  // JSON
  json: FileJson,
  jsonc: FileJson,
  // Text / docs
  md: FileText,
  mdx: FileText,
  markdown: FileText,
  txt: FileText,
  rtf: FileText,
  // Images
  png: FileImage,
  jpg: FileImage,
  jpeg: FileImage,
  gif: FileImage,
  webp: FileImage,
  bmp: FileImage,
  ico: FileImage,
  svg: FileImage,
  // Archives
  zip: FileArchive,
  tar: FileArchive,
  gz: FileArchive,
  "7z": FileArchive,
  rar: FileArchive,
  // Video / audio
  mp4: FileVideo,
  mov: FileVideo,
  webm: FileVideo,
  mkv: FileVideo,
  avi: FileVideo,
  mp3: FileAudio,
  wav: FileAudio,
  ogg: FileAudio,
  flac: FileAudio,
  // Config / dotfiles
  lock: File,
  env: File,
  gitignore: File,
  gitattributes: File,
  editorconfig: File,
};

/**
 * Derive an extension string from an FsNode. Prefers the explicit `ext` field,
 * else falls back to the substring after the last dot. Files with no dot
 * (e.g. `Dockerfile`) return an empty string.
 */
export function getNodeExtension(node: FsNode): string {
  if (node.ext) return node.ext.replace(/^\./, "").toLowerCase();
  const idx = node.name.lastIndexOf(".");
  if (idx <= 0 || idx === node.name.length - 1) return "";
  return node.name.slice(idx + 1).toLowerCase();
}

/**
 * Public consumer helper. Returns a JSX element for the given extension
 * string, falling back to a generic `<File>`. Does NOT take an FsNode —
 * consumers building custom registries can chain on this for their unknown
 * types.
 */
export function iconForExtension(
  ext: string,
  className = "size-4",
): ReactNode {
  const normalized = ext.replace(/^\./, "").toLowerCase();
  const Icon = EXT_TO_ICON[normalized] ?? File;
  return <Icon className={className} />;
}

/** Default icon for a file node — internal use. */
export function defaultFileIcon(node: FsNode, className = "size-4"): ReactNode {
  return iconForExtension(getNodeExtension(node), className);
}

/** Default icon for a folder node — internal use. */
export function defaultFolderIcon(
  expanded: boolean,
  className = "size-4",
): ReactNode {
  const Icon = expanded ? FolderOpen : Folder;
  return <Icon className={className} />;
}

import type { FsNode } from "../types";

/**
 * Flat-index a hierarchical array by id. Walks every node once, ignoring
 * cycles produced by malformed input (a node already in the index is skipped).
 */
export function indexNodes(nodes: FsNode[]): Map<string, FsNode> {
  const map = new Map<string, FsNode>();
  const walk = (list: FsNode[]) => {
    for (const node of list) {
      if (map.has(node.id)) continue;
      map.set(node.id, node);
      if (node.children) walk(node.children);
    }
  };
  walk(nodes);
  return map;
}

/** Find one node by id by walking the tree. Stops at first hit. */
export function findNode(
  id: string,
  nodes: FsNode[],
): FsNode | undefined {
  for (const node of nodes) {
    if (node.id === id) return node;
    if (node.children) {
      const hit = findNode(id, node.children);
      if (hit) return hit;
    }
  }
  return undefined;
}

/** Returns the chain of ancestor nodes (root → ... → parent) for `nodeId`. */
export function getParentChain(
  nodeId: string,
  index: Map<string, FsNode>,
): FsNode[] {
  const chain: FsNode[] = [];
  let current = index.get(nodeId);
  while (current?.parentId) {
    const parent = index.get(current.parentId);
    if (!parent) break;
    chain.unshift(parent);
    current = parent;
  }
  return chain;
}

/** All descendant ids of `nodeId` (excluding itself). */
export function getDescendantIds(
  nodeId: string,
  index: Map<string, FsNode>,
): Set<string> {
  const out = new Set<string>();
  const node = index.get(nodeId);
  if (!node?.children) return out;
  const walk = (list: FsNode[]) => {
    for (const child of list) {
      if (out.has(child.id)) continue;
      out.add(child.id);
      if (child.children) walk(child.children);
    }
  };
  walk(node.children);
  return out;
}

/**
 * Default sort: folders before files, then case-insensitive locale alpha by name.
 */
export function defaultSort(a: FsNode, b: FsNode): number {
  if (a.type !== b.type) return a.type === "folder" ? -1 : 1;
  return a.name.localeCompare(b.name, undefined, { sensitivity: "base" });
}

/** Initial uncontrolled-mode expanded set: every top-level folder id. */
export function deriveRootExpandedIds(nodes: FsNode[]): Set<string> {
  const set = new Set<string>();
  for (const node of nodes) {
    if (node.type === "folder") set.add(node.id);
  }
  return set;
}

/**
 * Recursive, immutable update — replaces a folder's `children` everywhere
 * in the tree without mutating the input array. Used by both
 * `mergeLoadedChildren` and other consumer helpers.
 */
function replaceChildren(
  nodes: FsNode[],
  parentId: string,
  next: FsNode[],
): FsNode[] {
  let changed = false;
  const out = nodes.map((node) => {
    if (node.id === parentId) {
      changed = true;
      return { ...node, children: next };
    }
    if (node.children) {
      const replaced = replaceChildren(node.children, parentId, next);
      if (replaced !== node.children) {
        changed = true;
        return { ...node, children: replaced };
      }
    }
    return node;
  });
  return changed ? out : nodes;
}

/**
 * Public consumer helper. After `onLoadChildren` resolves, splice the new
 * children into the right folder immutably.
 *
 *   onLoadChildren={async ({ nodeId }) => {
 *     const kids = await fs.list(nodeId);
 *     setNodes((prev) => mergeLoadedChildren(prev, nodeId, kids));
 *     return kids;
 *   }}
 */
export function mergeLoadedChildren(
  nodes: FsNode[],
  parentId: string,
  children: FsNode[],
): FsNode[] {
  return replaceChildren(nodes, parentId, children);
}

/** Total node count (recursive). */
export function countAllNodes(nodes: FsNode[]): number {
  let total = 0;
  const walk = (list: FsNode[]) => {
    for (const node of list) {
      total += 1;
      if (node.children) walk(node.children);
    }
  };
  walk(nodes);
  return total;
}

import type { FsNode, FileTreeDropPosition } from "../types";

/** True iff any source id equals the target id. */
export function isSelfDrop(
  srcIds: string[],
  targetId: string | null,
): boolean {
  if (!targetId) return false;
  return srcIds.includes(targetId);
}

/**
 * True iff dropping `srcIds` into / next-to `targetId` would create a cycle.
 * Walks the parent chain of the target; if any ancestor is in `srcIds`, the
 * move is illegal.
 */
export function isCycle(
  srcIds: string[],
  targetId: string | null,
  index: Map<string, FsNode>,
): boolean {
  if (!targetId) return false;
  const set = new Set(srcIds);
  let current: FsNode | undefined = index.get(targetId);
  while (current) {
    if (set.has(current.id)) return true;
    const parentId = current.parentId;
    if (!parentId) break;
    current = index.get(parentId);
  }
  return false;
}

export interface IsLegalDropArgs {
  srcIds: string[];
  targetId: string | null;
  position: FileTreeDropPosition;
  index: Map<string, FsNode>;
}

/**
 * Combined legality check. The tree refuses cycle / self-drop universally;
 * name-collision is a consumer-policy concern and not blocked here.
 */
export function isLegalDrop({
  srcIds,
  targetId,
  position,
  index,
}: IsLegalDropArgs): boolean {
  if (srcIds.length === 0) return false;
  if (isSelfDrop(srcIds, targetId)) return false;
  if (position === "inside" && isCycle(srcIds, targetId, index)) return false;
  if (position !== "inside" && targetId) {
    // before/after: cycle check uses the target's parent
    const target = index.get(targetId);
    const parentId = target?.parentId ?? null;
    if (isCycle(srcIds, parentId, index)) return false;
  }
  return true;
}

/**
 * Soft-validates a node tree on mount. Returns an array of warnings; never
 * throws. Caller logs to `console.warn` in development. Catches: duplicate
 * ids, missing parents (parentId references a node not in the tree), and
 * structural cycles (a node ancestor-of-itself).
 */
export function validateNodes(nodes: FsNode[]): string[] {
  const warnings: string[] = [];
  const ids = new Set<string>();
  const seenInPath = new Set<string>();
  const walk = (list: FsNode[], path: Set<string>) => {
    for (const node of list) {
      if (ids.has(node.id)) {
        warnings.push(`duplicate node id: "${node.id}"`);
        continue;
      }
      ids.add(node.id);
      if (path.has(node.id)) {
        warnings.push(`cycle detected at node: "${node.id}"`);
        continue;
      }
      if (node.children) {
        const next = new Set(path);
        next.add(node.id);
        walk(node.children, next);
      }
    }
  };
  walk(nodes, seenInPath);
  // parent-id sanity (advisory — parentId is optional)
  for (const node of ids) {
    void node;
  }
  return warnings;
}

"use client";

import type { CSSProperties, MouseEvent, ReactNode, KeyboardEvent } from "react";
import { ChevronRight, Loader2 } from "lucide-react";
import { cn } from "@/lib/utils";
import type {
  FileTreeDropPosition,
  FileTreeLabels,
  FileTreeRow,
  FileTreeValidateRenameArgs,
  FsNode,
} from "../types";
import { defaultFileIcon, defaultFolderIcon } from "../lib/icons";
import { FileTreeRenameInput } from "./file-tree-rename-input";

interface FileTreeRowProps {
  row: FileTreeRow;
  indent: number;
  indentGuides: boolean;
  rowHeight: number;
  iconForNode?: (args: { node: FsNode }) => ReactNode;
  isRenaming: boolean;
  validateRename?: (args: FileTreeValidateRenameArgs) => string | null;
  enableInternalDrag: boolean;
  /** Drop-target visual state for this row — set only when this row is the current hover target. */
  dropPosition?: FileTreeDropPosition | null;
  dropInvalid?: boolean;
  /** Lazy-load error message for this folder — when set, an error sub-row replaces the children area. */
  loadError?: string;
  onRetryLoad?: () => void;
  labels: FileTreeLabels;
  // Callbacks from orchestrator
  onClick: (e: MouseEvent, row: FileTreeRow) => void;
  onChevronClick: (e: MouseEvent, row: FileTreeRow) => void;
  onDoubleClick: (e: MouseEvent, row: FileTreeRow) => void;
  onContextMenu: (e: MouseEvent, row: FileTreeRow) => void;
  onRenameCommit: (id: string, nextName: string) => void;
  onRenameCancel: () => void;
  onDragStart?: (e: React.DragEvent, row: FileTreeRow) => void;
  onDragOver?: (e: React.DragEvent, row: FileTreeRow) => void;
  onDragLeave?: (e: React.DragEvent, row: FileTreeRow) => void;
  onDrop?: (e: React.DragEvent, row: FileTreeRow) => void;
  onDragEnd?: (e: React.DragEvent, row: FileTreeRow) => void;
  onRowKeyDown?: (e: KeyboardEvent<HTMLDivElement>, row: FileTreeRow) => void;
  /** Used as `style` on the outer div; lets the row-list place rows absolutely in virtual mode. */
  outerStyle?: CSSProperties;
}

const MAX_INDENT_PX = 200;

export function FileTreeRowComponent(props: FileTreeRowProps) {
  const {
    row,
    indent,
    indentGuides,
    rowHeight,
    iconForNode,
    isRenaming,
    validateRename,
    enableInternalDrag,
    dropPosition,
    dropInvalid,
    loadError,
    onRetryLoad,
    labels,
    onClick,
    onChevronClick,
    onDoubleClick,
    onContextMenu,
    onRenameCommit,
    onRenameCancel,
    onDragStart,
    onDragOver,
    onDragLeave,
    onDrop,
    onDragEnd,
    onRowKeyDown,
    outerStyle,
  } = props;

  const { node, depth, expanded, selected, focused, hasChildren, loadingChildren } =
    row;
  const isFolder = node.type === "folder";

  const computedIndent = Math.min(depth * indent, MAX_INDENT_PX);
  const dropClass = dropInvalid ? "ring-2 ring-destructive" : "";
  const insideDrop = dropPosition === "inside";

  const icon = node.icon
    ? node.icon
    : iconForNode
      ? iconForNode({ node })
      : isFolder
        ? defaultFolderIcon(expanded)
        : defaultFileIcon(node);

  return (
    <div className="relative" style={outerStyle}>
      {/* before / after drop indicator (line) */}
      {dropPosition === "before" && !dropInvalid ? (
        <div
          aria-hidden="true"
          className="pointer-events-none absolute left-0 right-0 top-0 z-10 h-0.5 bg-primary"
        />
      ) : null}
      {dropPosition === "after" && !dropInvalid ? (
        <div
          aria-hidden="true"
          className="pointer-events-none absolute bottom-0 left-0 right-0 z-10 h-0.5 bg-primary"
        />
      ) : null}

      <div
        role="treeitem"
        data-row-id={node.id}
        aria-level={depth + 1}
        aria-expanded={isFolder ? expanded : undefined}
        aria-selected={selected}
        aria-setsize={row.siblingCount}
        aria-posinset={row.siblingIndex}
        tabIndex={focused ? 0 : -1}
        draggable={enableInternalDrag && !isRenaming}
        onClick={(e) => onClick(e, row)}
        onDoubleClick={(e) => onDoubleClick(e, row)}
        onContextMenu={(e) => onContextMenu(e, row)}
        onDragStart={(e) =>
          enableInternalDrag && onDragStart && onDragStart(e, row)
        }
        onDragOver={(e) => onDragOver?.(e, row)}
        onDragLeave={(e) => onDragLeave?.(e, row)}
        onDrop={(e) => onDrop?.(e, row)}
        onDragEnd={(e) => onDragEnd?.(e, row)}
        onKeyDown={(e) => onRowKeyDown?.(e, row)}
        className={cn(
          "group relative flex cursor-pointer select-none items-center gap-1.5 px-2 text-sm",
          "rounded-sm",
          "outline-none transition-colors",
          selected
            ? "bg-secondary text-secondary-foreground"
            : "hover:bg-muted/60",
          focused && "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-inset",
          insideDrop && !dropInvalid && "ring-2 ring-primary",
          dropClass,
        )}
        style={{ height: `${rowHeight}px` }}
      >
        {/* indent guides */}
        {indentGuides
          ? Array.from({ length: depth }).map((_, i) => (
              <span
                key={i}
                aria-hidden="true"
                className="pointer-events-none absolute top-0 h-full w-px bg-border/50"
                style={{
                  left: `${Math.min((i + 1) * indent, MAX_INDENT_PX) - 1}px`,
                }}
              />
            ))
          : null}

        {/* indent spacer */}
        <span
          aria-hidden="true"
          className="shrink-0"
          style={{ width: `${computedIndent}px` }}
        />

        {/* chevron OR spacer */}
        {isFolder && hasChildren ? (
          <button
            type="button"
            tabIndex={-1}
            aria-label={expanded ? "Collapse" : "Expand"}
            onClick={(e) => {
              e.stopPropagation();
              onChevronClick(e, row);
            }}
            className="flex size-4 shrink-0 items-center justify-center text-muted-foreground hover:text-foreground"
          >
            {loadingChildren ? (
              <Loader2 className="size-3.5 animate-spin" aria-hidden="true" />
            ) : (
              <ChevronRight
                aria-hidden="true"
                className={cn(
                  "size-3.5 transition-transform",
                  expanded && "rotate-90",
                )}
              />
            )}
          </button>
        ) : (
          <span
            aria-hidden="true"
            className="size-4 shrink-0"
          />
        )}

        {/* icon */}
        <span
          aria-hidden="true"
          className={cn(
            "shrink-0",
            isFolder
              ? "text-amber-600 dark:text-amber-400"
              : "text-muted-foreground",
            selected && "text-secondary-foreground",
          )}
        >
          {icon}
        </span>

        {/* label OR rename input */}
        {isRenaming ? (
          <FileTreeRenameInput
            node={node}
            validateRename={validateRename}
            onCommit={(next) => onRenameCommit(node.id, next)}
            onCancel={onRenameCancel}
          />
        ) : (
          <span
            className="min-w-0 flex-1 truncate"
            title={node.name}
          >
            {node.name}
          </span>
        )}
      </div>

      {/* lazy-load error sub-row */}
      {loadError ? (
        <div
          role="alert"
          className="flex items-center gap-2 px-2 py-1 text-xs text-destructive"
          style={{
            paddingLeft: `${Math.min((depth + 1) * indent + 8, MAX_INDENT_PX) + 8}px`,
          }}
        >
          <span>{labels.loadError}: {loadError}</span>
          {onRetryLoad ? (
            <button
              type="button"
              onClick={(e) => {
                e.stopPropagation();
                onRetryLoad();
              }}
              className="rounded-sm border border-destructive px-1.5 py-0.5 text-xs hover:bg-destructive/10"
            >
              {labels.retry}
            </button>
          ) : null}
        </div>
      ) : null}

      {/* (empty) placeholder for known-empty folders that are expanded */}
      {isFolder &&
      expanded &&
      node.children !== undefined &&
      node.children.length === 0 &&
      !loadError ? (
        <div
          aria-hidden="true"
          className="px-2 py-1 text-xs italic text-muted-foreground"
          style={{
            paddingLeft: `${Math.min((depth + 1) * indent + 8, MAX_INDENT_PX) + 16}px`,
          }}
        >
          (empty)
        </div>
      ) : null}
    </div>
  );
}

